class Stack {
    int[] array;
    int top;
    public Stack(int size) {
        array = new int[size];
        top = -1;
    }
    public void push(int value) {
        array[++top] = value;
    }
    public int pop() {
        return array[top--];
    }
}

class Queue {
    int[] array;
    int front;
    int rear;
    public Queue(int size) {
        array = new int[size];
        front = rear = -1;
    }
    public void enqueue(int value) {
        array[++rear] = value;
    }
    public int dequeue() {
        return array[front++];
    }
}

