class HashTable {
    int[] array;
    public HashTable(int size) {
        array = new int[size];
    }
    public void put(int key, int value) {
        int index = hash(key);
        array[index] = value;
    }
    public int get(int key) {
        int index = hash(key);
        return array[index];
    }
    public int hash(int key) {
        return key % array.length;
    }
}

