public int fibonacci(int n) {
    int[] memo = new int[n + 1];
    for (int i = 0; i <= n; i++) {
        memo[i] = -1;
    }
    return fibonacci(n, memo);
}

private int fibonacci(int n, int[] memo) {
    if (n == 0 || n == 1) {
        return n;
    } else if (memo[n] != -1) {
        return memo[n];
    } else {
        int result = fibonacci(n - 1, memo) + fibonacci(n - 2, memo);
        memo[n] = result;
        return result;
    }
}

public class Graph {
    private int numNodes;
    private int[][] adjacencyMatrix;

    public Graph(int numNodes) {
        this.numNodes = numNodes;
        this.adjacencyMatrix = new int[numNodes][numNodes];
    }

    public void addEdge(int node1, int node2) {
        adjacencyMatrix[node1][node2] = 1;
        adjacencyMatrix[node2][node1] = 1;
    }

    public void printGraph() {
        for (int i = 0; i < numNodes; i++) {
            for (int j = 0; j < numNodes; j++) {
                System.out.print(adjacencyMatrix[i][j] + " ");
            }
            System.out.println();
        }
    }
}

public int maxSumSubarray(int[] array, int windowSize) {
    int maxSum = Integer.MIN_VALUE;
    int currentSum = 0;

    for (int i = 0; i < windowSize; i++) {
        currentSum += array[i];
    }

    maxSum = currentSum;

    for (int i = windowSize; i < array.length; i++) {
        currentSum = currentSum - array[i - windowSize] + array[i];
        maxSum = Math.max(maxSum, currentSum);
    }

    return maxSum;
}

