def shortest_substring_with_repeating_chars(s):
    char_count = {}
    left = 0
    min_length = float('inf')
    for right in range(len(s)):
        char_count[s[right]] = char_count.get(s[right], 0) + 1
        while char_count[s[right]] > 1:
            char_count[s[left]] -= 1
            left += 1
        min_length = min(min_length, right - left + 1)
    return min_length
