def max_sum_subarray_with_variable_size(arr):
    max_sum = float('-inf')
    for window_size in range(1, len(arr) + 1):
        for i in range(len(arr) - window_size + 1):
            window_sum = sum(arr[i:i + window_size])
            max_sum = max(max_sum, window_sum)
    return max_sum
